&lt;style&gt;
  .auth-page {
    min-height: calc(100vh - 72px);
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 60px 20px;
    background: linear-gradient(135deg, #fff0f6 0%, #f5eeff 100%);
  }

  .auth-card {
    background: white;
    border-radius: var(--radius-lg);
    padding: 48px 40px;
    width: 100%;
    max-width: 480px;
    box-shadow: var(--shadow-lg);
    border: 1px solid rgba(212, 80, 122, .08);
  }

  .auth-logo {
    text-align: center;
    margin-bottom: 32px;
  }

  .auth-logo h2 {
    font-family: var(--font-display);
    font-size: 1.8rem;
    color: var(--charcoal);
    margin-bottom: 4px;
  }

  .auth-logo h2 span { color: var(--rose); }
  .auth-logo p { font-size: .9rem; color: #aaa; }

  /* OAuth */
  .oauth-group { display: flex; flex-direction: column; gap: 12px; margin-bottom: 28px; }

  .oauth-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 13px;
    border-radius: var(--radius);
    font-size: .9rem;
    font-weight: 600;
    border: 1.5px solid var(--gray-light);
    background: white;
    color: var(--charcoal);
    cursor: pointer;
    transition: var(--transition);
    text-decoration: none;
  }

  .oauth-btn:hover {
    border-color: var(--rose);
    background: var(--rose-light);
    color: var(--rose-deep);
  }

  .oauth-btn.facebook {
    background: #1877f2;
    color: white;
    border-color: #1877f2;
  }

  .oauth-btn.facebook:hover {
    background: #166fe5;
    color: white;
    border-color: #166fe5;
  }

  .divider {
    display: flex;
    align-items: center;
    gap: 12px;
    margin: 24px 0;
  }

  .divider::before,
  .divider::after {
    content: &#039;&#039;;
    flex: 1;
    height: 1px;
    background: var(--gray-light);
  }

  .divider span {
    font-size: .78rem;
    color: #ccc;
    text-transform: uppercase;
    letter-spacing: .08em;
    font-weight: 600;
  }

  /* Errores */
  .error-box {
    background: #fff0f4;
    border: 1.5px solid var(--rose-light);
    border-radius: var(--radius);
    padding: 14px 16px;
    margin-bottom: 20px;
  }

  .error-box div {
    font-size: .85rem;
    color: var(--rose-deep);
    margin-bottom: 4px;
  }

  .error-box div:last-child { margin-bottom: 0; }

  /* Indicador de fortaleza de contraseña */
  .password-strength {
    margin-top: 8px;
    display: flex;
    gap: 4px;
  }

  .strength-bar {
    height: 4px;
    flex: 1;
    border-radius: 2px;
    background: var(--gray-light);
    transition: var(--transition);
  }

  .strength-bar.active.weak   { background: #f44336; }
  .strength-bar.active.medium { background: #ff9800; }
  .strength-bar.active.strong { background: #4caf50; }

  .strength-label {
    font-size: .75rem;
    color: #bbb;
    margin-top: 6px;
  }

  /* Términos */
  .terms-check {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    margin: 16px 0 20px;
  }

  .terms-check input[type=&quot;checkbox&quot;] {
    margin-top: 3px;
    accent-color: var(--rose);
    width: 16px;
    height: 16px;
    flex-shrink: 0;
    cursor: pointer;
  }

  .terms-check label {
    font-size: .83rem;
    color: #888;
    cursor: pointer;
    font-weight: 400;
    margin-bottom: 0;
  }

  .terms-check a { color: var(--rose); font-weight: 600; }

  /* Footer */
  .auth-footer {
    text-align: center;
    margin-top: 24px;
    font-size: .88rem;
    color: #aaa;
  }

  .auth-footer a { color: var(--rose); font-weight: 600; }

  /* Beneficios rápidos */
  .register-benefits {
    display: flex;
    flex-direction: column;
    gap: 8px;
    background: var(--gray-light);
    border-radius: var(--radius);
    padding: 16px 20px;
    margin-bottom: 24px;
  }

  .benefit-item {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: .83rem;
    color: #666;
  }

  .benefit-item i {
    color: var(--rose);
    font-size: 12px;
    width: 14px;
  }
&lt;/style&gt;

